mapper.select:
SELECT o.id, o.order_no AS orderNo, o.user_id AS userId, u.username AS username, o.show_id AS showId, s.name AS showTitle, s.poster AS showCover, o.theater_id AS theaterId, t.name AS theaterName, o.session_id AS sessionId, ss.show_time AS showTime, o.seat_count AS seatCount, o.total_price AS totalPrice, o.status, o.pay_method AS payMethod, o.pay_time AS payTime, o.create_time AS createTime FROM `order` o LEFT JOIN sys_user u ON o.user_id = u.id LEFT JOIN `show` s ON o.show_id = s.id LEFT JOIN theater t ON o.theater_id = t.id LEFT JOIN session ss ON o.session_id = ss.id WHERE o.deleted = 0
AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')
AND o.user_id = #{userId}
AND o.status = #{status}
ORDER BY o.create_time DESC
